import{_ as t,H as s,f as a,i}from"./chunks/framework.DbTCwA-u.js";const m=JSON.parse('{"title":"Installation et Prérequis","description":"Apprenez à installer EligiusNametag sur votre serveur Paper ou Folia.","frontmatter":{"title":"Installation et Prérequis","description":"Apprenez à installer EligiusNametag sur votre serveur Paper ou Folia."},"headers":[],"relativePath":"fr/installation.md","filePath":"fr/installation.md"}'),r={name:"fr/installation.md"};function n(l,e,o,d,u,c){return s(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="installation-et-prerequis" tabindex="-1">Installation et Prérequis <a class="header-anchor" href="#installation-et-prerequis" aria-label="Permalink to &quot;Installation et Prérequis&quot;">​</a></h1><p>EligiusNametag est un plugin moderne et puissant. En tirant parti des dernières fonctionnalités de l&#39;API de texte Minecraft et du multi-threading, il nécessite un environnement à jour.</p><h2 id="📋-prerequis-systeme" tabindex="-1">📋 Prérequis Système <a class="header-anchor" href="#📋-prerequis-systeme" aria-label="Permalink to &quot;📋 Prérequis Système&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Prérequis</th><th>Version Minimale</th><th>Raison</th></tr></thead><tbody><tr><td><strong>Plateforme</strong></td><td>Paper 1.21 ou Folia 1.21+</td><td>Utilisation stricte des composants <code>TEXT_DISPLAY</code> et des commandes Brigadier.</td></tr><tr><td><strong>Java</strong></td><td>Java 21 LTS</td><td>Code source compilé au format JDK 21.</td></tr></tbody></table><h2 id="📦-dependances" tabindex="-1">📦 Dépendances <a class="header-anchor" href="#📦-dependances" aria-label="Permalink to &quot;📦 Dépendances&quot;">​</a></h2><p>Vous devez installer les plugins suivants dans votre dossier <code>plugins/</code> :</p><ol><li><strong>ProtocolLib</strong> <em>(Requis)</em> : Utilisé pour envoyer les paquets d&#39;hologrammes de manière invisible sans consommer de TPS physiques.</li><li><strong>Vault</strong> <em>(Optionnel)</em> : Si vous souhaitez accorder des designs de nametag spécifiques selon le rang de l&#39;utilisateur (Admin, VIP, etc.).</li><li><strong>PlaceholderAPI</strong> <em>(Optionnel)</em> : Pour analyser des variables externes telles que les statistiques, l&#39;argent ou les clans dans les nametags.</li><li><strong>ItemsAdder</strong> <em>(Optionnel)</em> : Pour afficher des émojis personnalisés dans les noms.</li></ol><h2 id="🚀-etapes-d-installation" tabindex="-1">🚀 Étapes d&#39;Installation <a class="header-anchor" href="#🚀-etapes-d-installation" aria-label="Permalink to &quot;🚀 Étapes d&#39;Installation&quot;">​</a></h2><ol><li>Téléchargez le fichier <code>EligiusNametag-1.x.x.jar</code> depuis l&#39;onglet <strong>Releases</strong>.</li><li>Copiez le fichier dans le répertoire <code>plugins/</code> de votre serveur.</li><li>Assurez-vous d&#39;avoir installé <strong>ProtocolLib</strong>.</li><li>Démarrez votre serveur.</li><li>Vous verrez l&#39;animation de démarrage dans la console avec le chat Eligius MC confirmant que le plugin s&#39;est connecté avec succès.</li><li>Terminé ! Vous pouvez tout configurer depuis <code>plugins/EligiusNametag/</code>.</li></ol>',9)])])}const g=t(r,[["render",n]]);export{m as __pageData,g as default};
